-- Auto-generated from NY Medicaid Dental 2026 PDF
create schema if not exists coding_agent;

create table if not exists coding_agent.rule_sources ( id bigserial primary key, source_slug text not null unique, title text not null, payer_name text not null, source_file text, effective_date date, ingested_at timestamptz not null default now());

create table if not exists coding_agent.cdt_code_master ( code text primary key, short_description text not null, section_label text, source_id bigint not null references coding_agent.rule_sources(id) on delete cascade, source_page int, raw_text text, created_at timestamptz not null default now());

create table if not exists coding_agent.cdt_payer_rules ( id bigserial primary key, code text not null references coding_agent.cdt_code_master(code) on delete cascade, payer_name text not null, rule_type text not null, rule_text text not null, conditions jsonb not null default '{}'::jsonb, source_id bigint not null references coding_agent.rule_sources(id) on delete cascade, source_page int, created_at timestamptz not null default now());

create index if not exists cdt_payer_rules_code_idx on coding_agent.cdt_payer_rules(code);
create index if not exists cdt_payer_rules_type_idx on coding_agent.cdt_payer_rules(rule_type);

insert into coding_agent.rule_sources (source_slug, title, payer_name, source_file, effective_date) values ('nys_medicaid_dental_2026', 'NYS Medicaid Dental Policy and Procedure Code Manual 2026', 'New York State Medicaid', 'dental_policy_and_procedure_manual.pdf', '2026-01-01') on conflict (source_slug) do update set title = excluded.title, payer_name = excluded.payer_name, source_file = excluded.source_file, effective_date = excluded.effective_date;

with src as (
  select id from coding_agent.rule_sources where source_slug = 'nys_medicaid_dental_2026'
)
insert into coding_agent.cdt_code_master (code, short_description, section_label, source_id, source_page, raw_text)
values
  ('D0120', 'Periodic oral evaluation – established patient', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 25, 'D0120 Periodic oral evaluation – established patient An evaluation performed on a patient of record to determine any changes in the patient''s dental and medical health status since a previous comprehensive or periodic evaluation. This includes an oral cancer evaluation, periodontal screening where indicated and may require interpretation of information acquired through additional diagnostic procedures. The findings are discussed with the patient. Report additional diagnostic procedures separately. Reimbursement is limited to once per six (6) month period. $25.25'),
  ('D0140', 'Limited oral evaluation – problem focused', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 25, 'D0140 Limited oral evaluation – problem focused An evaluation limited to a specific oral health problem or complaint. This may require interpretation of information acquired through additional diagnostic procedures. Report additional diagnostic procedures separately. Definitive procedures may be required on the same date as the evaluation. Typically, patients receiving this type of evaluation present with a specific problem and/or dental emergencies, trauma, acute infections, etc. Not used in conjunction with a regular appointment. Cannot be billed with any other evaluation procedure, including but not limited to D9310 and D9430. Not intended for follow-up care. $14.14'),
  ('D0145', 'Oral evaluation for a patient under three years of age and counseling with primary caregiver', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 25, 'D0145 Oral evaluation for a patient under three years of age and counseling with primary caregiver Diagnostic services performed for a child under the age of three, preferably within the first six months of the eruption of the first primary tooth, including recording the oral and physical health history, evaluation of caries susceptibility, development of an appropriate preventive oral health regimen and communication with and counseling of the child''s parent, legal guardian and/or primary caregiver. $30.30'),
  ('D0150', 'Comprehensive oral evaluation – new or established patient', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 25, 'D0150 Comprehensive oral evaluation – new or established patient Used by a general dentist and/or a specialist when evaluating a patient comprehensively. It is a thorough evaluation and recording of the extraoral and intraoral hard and soft tissues. It may require interpretation of information acquired through additional diagnostic procedures. Additional diagnostic procedures should be reported separately. This includes an evaluation for oral cancer, the evaluation and recording of the patient''s dental and medical history and a general health assessment. It includes the evaluation and recording of dental caries, missing or unerupted teeth, restorations, existing prostheses, occlusal relationships, periodontal conditions (including periodontal screening and/or charting), hard and soft tissue anomalies, etc. Can only be billed once per provider-member relationship. $30.30'),
  ('D0160', 'Detailed and extensive oral evaluation – problem focused, by report (REPORT NEEDED)', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 25, 'D0160 Detailed and extensive oral evaluation – problem focused, by report (REPORT NEEDED) A detailed and extensive problem focused evaluation entails extensive diagnostic and cognitive modalities based on the findings of a comprehensive oral evaluation. Integration of more extensive diagnostic modalities to develop a treatment plan for a specific problem is required. The condition requiring this type of evaluation should be described and documented. This procedure will not be reimbursed if performed within ninety days of a consultation or any other evaluation by the same provider. (BR) DIAGNOSTIC IMAGING The most current recommendations for prescribing dental radiographs should be followed. Revised guidance from ADA, HHS, and FDA can be found at: Optimizing radiation safety in dentistry - The Journal of the American Dental Association (ada.org). This information should guide the dentist in the determination of the type of imaging to be used, the frequency of its use, and the number of images to obtain. All images taken should be medically necessary and of diagnostic quality, properly identified, and dated. Claims for dental radiographs may be pended for professional review and are subject to denial unless there is a documented need of medical necessity. Capture and interpretation of intraoral images are not separately reimbursed by this program. When ordering a CT, CTA, MRI, MRA, Cardiac Nuclear, or PET procedure an approval number through the Radiology Prior Approval Program is required. For additional information refer to: http://www.emedny.org/ProviderManuals/Radiology/index.html. Note: The Radiology Prior Approval Program does not include procedure codes D0364-D0368, cone beam computed tomography. For more information see description of D0364-D0368.'),
  ('D0210', 'Intraoral - comprehensive series of radiographic images', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 6, 'D0210 Intraoral – Comprehensive Series of Radiographic Images Addition of Language: Description of Intraoral – Comprehensive Series of Radiographic Images D0210 Intraoral - comprehensive series of radiographic images A radiographic survey of the whole mouth intended to display the crowns and roots of all teeth, periapical areas, interproximal areas and alveolar bone including edentulous areas. This can be used for complex treatment planning and diagnosis of periapical or periodontal pathology. This code is not reimbursable when a panoramic image has been taken within three years, except when medically necessary for the diagnosis of a new patient or new condition. For purposes of the NYS Medicaid program, an intraoral, comprehensive series (full mouth) consists of at least ten (10) periapical films plus bitewings. $50.50'),
  ('D0220', 'Intraoral - periapical first radiographic image', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 26, 'D0220 Intraoral - periapical first radiographic image To be billed for the FIRST periapical image and may be used in conjunction with other types of intraoral radiographs taken on the same date of service. $8.08'),
  ('D0230', 'Intraoral - periapical each additional radiographic image', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 26, 'D0230 Intraoral - periapical each additional radiographic image The total fee for ALL intraoral radiographic images (including the first periapical image) may not exceed the total fee allowed for a complete intraoral series. The frequency limit for periapical x-rays will be updated from three (3) times in 6 months to six (6) times in 12 months. $5.05'),
  ('D0240', 'Intraoral - occlusal radiographic image (ARCH)', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 26, 'D0240 Intraoral - occlusal radiographic image (ARCH) One maxillary and one mandibular radiographic image are allowed within three years. May be supplemented by necessary intraoral periapical or bitewing images. $15.15'),
  ('D0250', 'Extra-oral - 2D projection radiographic image created using a stationary radiation source, and', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 26, 'D0250 Extra-oral - 2D projection radiographic image created using a stationary radiation source, and detector These images include but are not limited to: Lateral Skull; Posterior-Anterior Skull; Submentovertex; Waters; Reverse Tomes; Oblique Mandibular Body; Lateral Ramus. Not reimbursable for Temporomandibular Joint images. $25.25'),
  ('D0251', 'Extra-oral posterior dental radiographic image', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 26, 'D0251 Extra-oral posterior dental radiographic image Image is limited to exposure of complete posterior teeth in both dental arches. This is a unique image that is not derived from another image. Maximum of two images. Not reimbursable for Temporomandibular Joint images. Bitewings are allowed no more than once in six months for $12.12 each member. The procedure code is an indication of the number of images performed. Leave the “Times Performed” on the claim form blank or enter “1”.'),
  ('D0270', 'Bitewing – single radiographic image $8.08', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0270 Bitewing – single radiographic image $8.08'),
  ('D0272', 'Bitewings – two radiographic images $14.14', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0272 Bitewings – two radiographic images $14.14'),
  ('D0273', 'Bitewings – three radiographic images $20.20', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0273 Bitewings – three radiographic images $20.20'),
  ('D0274', 'Bitewings – four radiographic images $24.24', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0274 Bitewings – four radiographic images $24.24'),
  ('D0310', 'Sialography $41.41', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0310 Sialography $41.41'),
  ('D0320', 'Temporomandibular joint arthrogram, including injection $175.74', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0320 Temporomandibular joint arthrogram, including injection $175.74'),
  ('D0321', 'Other temporomandibular joint radiographic images, by report (PER JOINT) (REPORT NEEDED) $29.29', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0321 Other temporomandibular joint radiographic images, by report (PER JOINT) (REPORT NEEDED) $29.29'),
  ('D0330', 'Panoramic radiographic image', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0330 Panoramic radiographic image Reimbursable every three years if clinically indicated. For use in routine caries determination, diagnosis of periapical or periodontal pathology only when supplemented by other necessary radiographic intraoral images (bitewing and/or periapical), completely edentulous cases, diagnosis of impacted teeth, oral surgery treatment planning, or diagnosis of children with mixed dentition. Postoperative panoramic images are reimbursable for post-surgical evaluation of fractures, dislocations, orthognathic surgery, osteomyelitis, or removal of unusually large and/or complex cysts or neoplasms. Panoramic radiographic images are not required or reimbursable for post orthodontic documentation. Panoramic images are not reimbursable when an intraoral complete series or panoramic image has been taken within three years, except for the diagnosis of a new condition (e.g., traumatic injury, orthodontic evaluation). A treating dental specialist can be reimbursed for a panoramic radiograph (panorex) even if one has been taken within three years, to render the necessary dental care when the panorex provided from the referring dentist is not diagnostic or cannot be obtained. Claims for payment should be accompanied by a narrative explaining the patient-specific medical necessity. See New York State Medicaid Update - July 2024 Volume 40 - Number 7 (ny.gov). $35.35'),
  ('D0340', '2D cephalometric radiographic image – acquisition, measurement and analysis', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 27, 'D0340 2D cephalometric radiographic image – acquisition, measurement and analysis Image of the head made using a cephalostat to standardize anatomic positioning, and with reproducible x -ray beam geometry. Reimbursable every three years if clinically indicated. Reimbursement is limited to enrolled orthodontists or oral and maxillofacial surgeons for the diagnosing and treatment of a physically handicapping malocclusion. Cephalometric images are not required by the DOH for routine post -orthodontic documentation and are not routinely reimbursable. A tracing and analysis are required and are not payable separately. Use D0252 if a tracing and analysis is not performed. $55.55'),
  ('D0350', '2D oral/facial photographic image obtained intra-orally or extra-orally', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 6, 'D0350 2D Oral/Facial Photographic Image; and PA Attachments Addition of Language and Links: Description of 2D Oral/Facial Photographic Image; and Instructions for Adding Attachment to a PA D0350 2D oral/facial photographic image obtained intra-orally or extra-orally Photographs are reimbursable when associated with procedures described under sections: • V. PERIODONTICS, limited to gingivectomy or gingivoplasty, procedure codes D4210, D4211, and clinical crown lengthening, procedure code D4249 • VIII. IMPLANTS • X. ORAL AND MAXILLOFACIAL SURGERY , limited to frenectomy, frenuloplasty, and frenulectomy, procedure codes D7961, D7962 • XI. ORTHODONTICS When requested by the Department of Health; and the fee includes all intra -oral and extra -oral images taken on the same date of service. For instructions on how to include attachments for a PA please follow the link: Electronic Attachments for Dental PAs. $12.12 CONE BEAM CT CAPTURE • Includes axial, coronal and sagittal data. • Includes all interpretation. • There is no professional reimbursement for facility place of service. Facility reimbursement is through APG. For treatment not involving implants or implant-related services, a panoramic radiograph (D0330) or similar film, along with documentation of medical necessity, must be submitted with requests for prior approval. Approval is limited to those cases demonstrating significant risk for a complication such as nerve injury or jaw fracture, as well as pathology or trauma workups. For treatment involving implants or implant-related services, refer to section VIII. IMPLANTS.'),
  ('D0364', 'Cone beam CT capture and interpretation with limited field of view – less than one whole jaw (PA', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0364 Cone beam CT capture and interpretation with limited field of view – less than one whole jaw (PA REQUIRED) $281.79'),
  ('D0365', 'Cone beam CT capture and interpretation with field of view of one full dental arch - mandible', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0365 Cone beam CT capture and interpretation with field of view of one full dental arch - mandible (PA REQUIRED) $281.79'),
  ('D0366', 'Cone beam CT capture and interpretation with field of view of one full dental arch – maxilla, with', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0366 Cone beam CT capture and interpretation with field of view of one full dental arch – maxilla, with or without cranium (PA REQUIRED) $281.79'),
  ('D0367', 'Cone beam CT capture and interpretation with field of view of both jaws; with or without', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0367 Cone beam CT capture and interpretation with field of view of both jaws; with or without cranium (PA REQUIRED) $281.79'),
  ('D0368', 'Cone beam CT capture and interpretation for TMJ series including two or more exposures (PA', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0368 Cone beam CT capture and interpretation for TMJ series including two or more exposures (PA REQUIRED) $281.79'),
  ('D0470', 'Diagnostic casts', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0470 Diagnostic casts Reimbursement is limited to enrolled orthodontists or oral and maxillofacial surgeons. Includes both arches when necessary. $34.34 ORAL PATHOLOGY LABORATORY These are procedures generally performed in a pathology laboratory and do not include the removal of the tissue sample from the patient. For removal of tissue sample, see codes D7285 and D7286. Reimbursement for procedure codes D0470, D0485 and D0502 are limited to enrolled Oral Pathologists.'),
  ('D0474', 'Accession of tissue, gross and microscopic examination, including assessment of surgical margins', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0474 Accession of tissue, gross and microscopic examination, including assessment of surgical margins for presence of disease, preparation and transmission of written report. $87.87'),
  ('D0485', 'Consultation, including preparation of slides from biopsy material supplied by referring source $87.87', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0485 Consultation, including preparation of slides from biopsy material supplied by referring source $87.87'),
  ('D0502', 'Other oral pathology procedures, by report (REPORT NEEDED) (BR)', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0502 Other oral pathology procedures, by report (REPORT NEEDED) (BR)'),
  ('D0999', 'Unspecified diagnostic procedure, by report (REPORT NEEDED) (BR)', 'I. DIAGNOSTIC D0100-D0999', (select id from src), 28, 'D0999 Unspecified diagnostic procedure, by report (REPORT NEEDED) (BR) DENTAL PROPHYLAXIS Dental prophylaxis is reimbursable in addition to an initial dental examination and recall examinations once per six (6) month period. Prophylaxis cannot be used in conjunction with periodontal maintenance (D4910) or in conjunction with scaling and root planing (D4341) on the same date of service. An additional prophylaxis may be considered within a twelve (12) month period for those individuals identified with a Restriction Exception code of RE 81 (“TBI Eligible”) or RE 95 (“OPWDD/Managed Care Exemption”). The additional prophylaxis should be submitted using the appropriate procedure code (D1110 or D1120). Documentation supporting necessity must be submitted with the claim. Reimbursement will not be considered if performed within a four-month interval of previous prophylaxis (D1110, D1120) or D4910.'),
  ('D1110', 'Prophylaxis – adult', 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', (select id from src), 29, 'D1110 Prophylaxis – adult Removal of plaque, calculus and stains from tooth structures and implants in the permanent and transitional dentition. It is intended to control local irritational factors. For members 13 years of age and older. $45.45 D1110 or'),
  ('D1120', 'Prophylaxis – child', 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', (select id from src), 29, 'D1120 Prophylaxis – child Removal of plaque, calculus and stains from tooth structures and implants in the primary and transitional dentition. It is intended to control local irritational factors. For members under 13 years of age. $43.43 TOPICAL FLUORIDE TREATMENT (OFFICE PROCEDURE) Topical fluoride treatment is reimbursable when professionally administered in accordance with appropriate standards. Benefit is limited to gel, foam, and varnish. There must be a minimum interval of three (3) months between all fluoride treatments (D1206 and/or D1208). Fluoride treatments that are not reimbursable under the program include: • Treatment that incorporates fluoride with prophylaxis paste; • Topical application of fluoride to the prepared portion of a tooth prior to restoration; • Fluoride rinse or “swish”; and • Treatment for desensitization. Note: FQHCs who opt out of Ambulatory Patient Groups (APG) cannot bill a separate threshold rate for Topical Fluoride Application (D1206, D1208, 99188) as a standalone procedure at a patient encounter where no other reimbursable services are delivered. D1120 Prophylaxis – adult or child Additional prophylaxis may be considered within a twelve-month period for those individuals identified with a Restriction Exception code of RE 81 or RE 95. No Yes'),
  ('D1206', 'Topical application of fluoride varnish', 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', (select id from src), 29, 'D1206 Topical application of fluoride varnish Reimbursable once per three (3) month period for members, from eruption of first tooth through age 20 (inclusive). For individuals 21 years of age and older D1206 is only approvable for those individuals identified with a Restriction Exception code of RE 81 (“TBI Eligible”) or RE 95 (“OPWDD/Managed Care Exemption”), or, in cases where salivary gland function has been compromised through surgery, radiation, or disease. Reimbursable to physicians and nurse practitioners under CPT code 99188. $30.30 D1206 Topical application of fluoride varnish Application once per 3-month period for individuals 21 years of age and older, identified with a Restriction Exception code of RE 81 or RE 95; Reimbursable in medical settings under CPT code 99188. No No'),
  ('D1208', 'is only approvable for those individuals identified with a Restriction Exception code of RE 81', 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', (select id from src), 29, 'D1208 Topical application of fluoride – excluding varnish Reimbursable once per six (6) month period for members between 6 and 20 years of age (inclusive). Fluoride must be applied separately from prophylaxis paste. For individuals 21 years of age and older D1208 is only approvable for those individuals identified with a Restriction Exception code of RE 81 (“TBI Eligible”) or RE 95 (“OPWDD/Managed Care Exemption”), or, in cases where salivary gland function has been compromised through surgery, radiation, or disease. $14.14 OTHER PREVENTATIVE SERVICES D1208 Topical Application of fluoride – excluding varnish Applied separately from prophylaxis paste; Reimbursable once per six-month period for individuals 21 years of age and older D1208 with a Restriction Exception code of RE 81 or RE 95. No No'),
  ('D1320', 'Tobacco counseling for the control and prevention of oral disease $10.10', 'II. PREVENTITIVE D1000-D1999', (select id from src), 29, 'D1320 Tobacco counseling for the control and prevention of oral disease $10.10 Tobacco prevention and cessation services reduce patient risks of developing tobacco-related oral diseases and conditions and improves prognosis for certain dental therapies. Reimbursement for smoking cessation counseling (SCC) must meet the following criteria: • SCC must be provided face-to-face by either a dentist or by a dental hygienist that is supervised by the dentist; • SCC must be billed by either an office-based dental practitioner or by an Article 28 clinic that employs a dentist; • Dental practitioners can only provide individual SCC services, which must be greater than three minutes in duration, NO group sessions are allowed; • Dental claims for SCC must include the CDT procedure code D1320 (tobacco counseling for the control and prevention of oral disease); • In a dental office or an Article 28 clinic, SCC should only take place during a dental visit as an adjunct when providing a dental service and NOT billed as a stand-alone service; • Smoking Cessation Counseling complements existing Medicaid covered benefits for prescription and non- prescription smoking cessation products including nasal sprays, inhalers, Zyban (bupropion), Chantix (varenicline), over-the counter nicotine patches and gum; • To receive reimbursement for SCC services the following information must be documented in the patient''s dental record: o At least 4 of 5 A''s: smoking status and if yes, willingness to quit; o If willing to quit, offer medication as needed, target date for quitting, and follow-up date (with documentation in the record that the follow-up occurred); o If unwilling to quit, the patient''s expressed roadblocks; o Referrals to the New York State Smoker''s Quitline and/or community services to address roadblocks and for additional cessation resources and counselling, if needed. Smoking cessation services are included in the prospective payment system (PPS) rate for those FQHCs that do not participate in APG reimbursement. Dentists should be aware of the following guideline for smoking cessation counseling: A Clinical Practice Guideline for Treating Tobacco Use and Dependence: 2008 Update - American Journal of Preventive Medicine, which demonstrated that efficacious treatments for tobacco users exist and should become a part of standard care giving.'),
  ('D1351', 'Sealant – per tooth (TOOTH) (DVS REQUIRED)', 'II. PREVENTITIVE D1000-D1999', (select id from src), 30, 'D1351 Sealant – per tooth (TOOTH) (DVS REQUIRED) Mechanically and/or chemically prepared enamel surface sealed to prevent decay. Refer to the “Prior Approval/Prior Authorization Requirements” section for use of DVS. Application of sealant is restricted to permanent first and second molars with unrestored occlusal surfaces that exhibit no signs of occlusal or proximal caries for members between 5 and 15 years of age (inclusive). Application to occlusal pits and fissures, as well as contiguous buccal and lingual grooves are included in the fee. The use of opaque or tinted sealant is recommended for ease of checking bond efficacy. Reapplication, if necessary, is permitted once every five (5) years. $35.35'),
  ('D1354', 'Application of caries arresting medicament – per tooth', 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', (select id from src), 30, 'D1354 Application of caries arresting medicament – per tooth Conservative treatment of an active, non-symptomatic carious lesion by topical application of a caries arresting or inhibiting medicament and without mechanical removal of sound tooth structure - Limited to Silver Diamine Fluoride Clinical criteria for the use of silver diamine fluoride: • Stabilize non-symptomatic teeth with active carious lesion and no pulpal exposure • Moderate-to-High caries risk (e.g. xerostomia, severe early childhood caries) • Treatment challenged by behavioral or medical management • Difficult to treat carious lesions $15.15 Criteria for reimbursement: • Covered two (2) times per tooth within a 12-month period with a total of four (4) times per lifetime of the tooth. • Covered with topical application of fluoride (“D1206” or “D1208”) when they are performed on the same date of service if “D1354” is being used to treat caries and “D1206” or “D1208” is being used to prevent caries. • Silver diamine fluoride may be applied to five (5) teeth on the same date of service with more teeth considered in exceptional circumstances. Documentation supporting necessity must be submitted with the claim. • Caries arresting medicament is not reimbursable when used as a base for a final restoration. Providers are required to: Fully disclose the risks and benefits of silver diamine fluoride use and to discuss treatment alternatives where appropriate. Obtain written consent. SPACE MAINTENANCE (PASSIVE APPLIANCES) Only fixed appliances are reimbursable. Documentation including pre-treatment images to justify all space maintenance appliances must be available upon request. Space maintenance should not be provided as an isolated service. All carious teeth must be restored before placement of any space maintainer. The member should be practicing a sufficient level of oral hygiene to ensure that the space maintainer will not become a source of further carious breakdown of the dentition. All permanent teeth in the area of space maintenance should be present and developing normally. Space maintenance in the deciduous dentition (defined as prior to the interdigitation of the first permanent molars) can generally be considered. Space maintenance in the mixed dentition initiated within one month of the necessary extraction will be reimbursable on an individual basis. Space maintenance in the mixed dentition initiated more than one month after the necessary extraction, with minimum space loss apparent, may be reimbursable. D1354 Application of caries arresting medicament – per tooth Covered two times per tooth within a 12 -month period with a total of four times per lifetime of the tooth. Use must meet stated clinical criteria: • Stabilize non -symptomatic teeth with active carious lesion and no pulpal exposure • Moderate to High caries risk (e.g. xerostomia, severe early childhood caries) • Treatment challenged by behavioral or medical management • Difficult to treat carious lesions No No'),
  ('D1510', 'Space maintainer – fixed, unilateral – per quadrant (QUAD)', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1510 Space maintainer – fixed, unilateral – per quadrant (QUAD) Excludes a distal show space maintainer. $117.16'),
  ('D1516', 'Space maintainer – fixed – bilateral, maxillary $175.75', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1516 Space maintainer – fixed – bilateral, maxillary $175.75'),
  ('D1517', 'Space maintainer – fixed – bilateral, mandibular $175.75', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1517 Space maintainer – fixed – bilateral, mandibular $175.75'),
  ('D1551', 'Re-cement or re-bond bilateral space maintainer – maxillary $19.19', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1551 Re-cement or re-bond bilateral space maintainer – maxillary $19.19'),
  ('D1552', 'Re-cement or re-bond bilateral space maintainer – mandibular $19.19', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1552 Re-cement or re-bond bilateral space maintainer – mandibular $19.19'),
  ('D1553', 'Re-cement or re-bond unilateral space maintainer – per quadrant (QUAD) $19.19', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1553 Re-cement or re-bond unilateral space maintainer – per quadrant (QUAD) $19.19'),
  ('D1575', 'Distal shoe space maintainer – fixed, unilateral, per quadrant (QUAD)', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1575 Distal shoe space maintainer – fixed, unilateral, per quadrant (QUAD) Fabrication and delivery of fixed appliance extending subgingivally and distally to guide the eruption of the first permanent molar. Does not include ongoing follow-up or adjustments, or replacement appliances, once the tooth has erupted. $117.16 Unless otherwise specified, the cost of analgesic and anesthetic agents is included in the reimbursement for the dental service. The maximum fee for restoring a tooth with either amalgam or composite resin material will be the fee allowed for placement of a four-surface restoration. With the exception of the placement of reinforcement pins (use code D2951), fees for amalgam and composite restorations include tooth preparation, all adhesives (including amalgam and composite bonding agents), acid etching, cavity liners, bases, curing and pulp capping. Caries index, periodontal status, and the overall status and prognosis of the entire dentition, as well as recipient compliance, dental history, and medical history, among other factors, will be taken into consideration when determining medical necessity. Treatment is considered appropriate where the prognosis of the tooth is favorable. Treatment may be appropriate where the total number of teeth which require or are likely to require treatment is not considered excessive or when maintenance of the tooth is considered essential or appropriate in view of the overall dental status of the recipient. Please review Scope of Program and Non-Reimbursable Services (p. 13) and Essential Services (p. 23). Restorations placed solely for the treatment of abrasion, attrition, erosion or abfraction and are not associated with the treatment of any other pathology are beyond the scope of the program and will not be reimbursed. Restorative procedures should not be performed without documentation of clinical necessity. Published “frequency limits” are general reference points on the anticipated frequency for that procedure. Actual frequency must be based on the clinical needs of the individual member. If a non-covered surgical procedure is required to properly restore a tooth, any associated restorative or endodontic treatment will NOT be considered for reimbursement. Note, this provision does not apply to crown lengthening, which will be considered for reimbursement when associated with any medically necessary crown or endodontic treatment. For codes D2140, D2330 and D2391, only a single restoration will be reimbursable per surface. Occlusal surface restorations including all occlusal pits and fissures will be reimbursed as one-surface restorations whether or not the transverse ridge of an upper molar is left intact. Codes D2150, D2160, D2161, D2331, D2332, D2335, D2781, D2392, D2393, and D2394 are compound restorations encompassing 2, 3, 4 or more contiguous surfaces. Restorations that connect contiguous surfaces must be billed using the appropriate multi-surface restorative procedure code. AMALGAM RESTORATIONS (INCLUDING POLISHING)'),
  ('D1999', 'Unspecified preventive procedure, by report (BR)', 'II. PREVENTITIVE D1000-D1999', (select id from src), 31, 'D1999 Unspecified preventive procedure, by report (BR) SPACE MAINTAINERS'),
  ('D2140', 'Amalgam - one surface, primary or permanent (SURF/TOOTH) $50.50', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2140 Amalgam - one surface, primary or permanent (SURF/TOOTH) $50.50'),
  ('D2150', 'Amalgam - two surfaces, primary or permanent (SURF/TOOTH) $67.67', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2150 Amalgam - two surfaces, primary or permanent (SURF/TOOTH) $67.67'),
  ('D2160', 'Amalgam - three surfaces, primary or permanent (SURF/TOOTH) $82.82', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2160 Amalgam - three surfaces, primary or permanent (SURF/TOOTH) $82.82'),
  ('D2161', 'Amalgam - four or more surfaces, primary or permanent (SURF/TOOTH) $98.98', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2161 Amalgam - four or more surfaces, primary or permanent (SURF/TOOTH) $98.98 RESIN-BASED COMPOSITE-RESTORATIONS DIRECT'),
  ('D2330', 'Resin-based composite - one surface, anterior (SURF/TOOTH) $50.50', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2330 Resin-based composite - one surface, anterior (SURF/TOOTH) $50.50'),
  ('D2331', 'Resin-based composite - two surfaces, anterior (SURF/TOOTH) $73.73', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2331 Resin-based composite - two surfaces, anterior (SURF/TOOTH) $73.73'),
  ('D2332', 'Resin-based composite - three surfaces, anterior (SURF/TOOTH) $87.87', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2332 Resin-based composite - three surfaces, anterior (SURF/TOOTH) $87.87'),
  ('D2335', 'Resin-based composite - four or more surfaces (anterior) (SURF/TOOTH) $98.98', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2335 Resin-based composite - four or more surfaces (anterior) (SURF/TOOTH) $98.98'),
  ('D2390', 'Resin-based composite crown, anterior (TOOTH) $98.98', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2390 Resin-based composite crown, anterior (TOOTH) $98.98'),
  ('D2391', 'Resin-based composite – one surface, posterior (SURF/TOOTH) $50.50', 'III. RESTORATIVE D2000-D2999', (select id from src), 32, 'D2391 Resin-based composite – one surface, posterior (SURF/TOOTH) $50.50'),
  ('D2392', 'Resin-based composite - two surfaces, posterior (SURF/TOOTH) $67.67', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2392 Resin-based composite - two surfaces, posterior (SURF/TOOTH) $67.67'),
  ('D2393', 'Resin-based composite - three surfaces, posterior (SURF/TOOTH) $82.82', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2393 Resin-based composite - three surfaces, posterior (SURF/TOOTH) $82.82'),
  ('D2394', 'Resin-based composite - four or more surfaces, posterior (SURF/TOOTH) $98.98', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2394 Resin-based composite - four or more surfaces, posterior (SURF/TOOTH) $98.98 CROWNS - SINGLE RESTORATIONS ONLY The materials used in the fabrication of a crown (e.g. all-metal, porcelain, ceramic, resin) is at the discretion of the provider. The crown fabricated must correctly match the procedure code approved on the Prior Approval. Crowns include any necessary core buildups. Crowns for members under the age of 21 will be covered when medically necessary. In determining whether a requested crown is medically necessary, the following factors may be considered: • The periodontal status, member compliance and overall status and prognosis of the tooth is favorable. • The tooth is not routinely restorable with a filling. Crowns for members 21 and over will be covered when medically necessary. In determining whether a requested crown is medically necessary, the following factors may be considered: • There is a documented medical condition which precludes an extraction. • The tooth is a critical abutment for an existing or proposed prosthesis. • If the tooth is a posterior tooth, the following additional factors may be considered: o The periodontal status, member compliance and overall status and prognosis of the tooth is favorable o The tooth is not routinely restorable with a filling o There are eight or more natural or prosthetic posterior points of contact present o If the posterior tooth is a molar, treatment of the molar is necessary to maintain functional or balanced occlusion of the patient''s dentition o Consideration for a third molar will be given if the third molar occupies the first or second molar position o Note: Requests for treatment on unopposed molars must include a narrative documenting medical necessity. • If the tooth is an anterior tooth, the following additional factors may be considered: o The periodontal status, member compliance and overall status and prognosis of the tooth is favorable o The tooth is not routinely restorable with a filling'),
  ('D2710', 'Crown – resin-based composite (indirect) (laboratory) (TOOTH) (PA REQUIRED)', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2710 Crown – resin-based composite (indirect) (laboratory) (TOOTH) (PA REQUIRED) Acrylic (processed) jacket crowns may be approved as restorations for severely fractured anterior teeth. $292.90'),
  ('D2720', 'Crown – resin with high noble metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2720 Crown – resin with high noble metal (TOOTH) (PA REQUIRED) $505.00'),
  ('D2721', 'Crown – resin with predominantly base metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2721 Crown – resin with predominantly base metal (TOOTH) (PA REQUIRED) $505.00'),
