  ('D2740', 'Crown – porcelain/ceramic (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2740 Crown – porcelain/ceramic (TOOTH) (PA REQUIRED) $505.00'),
  ('D2750', 'Crown – porcelain fused to high noble metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2750 Crown – porcelain fused to high noble metal (TOOTH) (PA REQUIRED) $505.00'),
  ('D2751', 'Crown – porcelain fused to predominately base metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2751 Crown – porcelain fused to predominately base metal (TOOTH) (PA REQUIRED) $505.00'),
  ('D2752', 'Crown – porcelain fused to noble metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2752 Crown – porcelain fused to noble metal (TOOTH) (PA REQUIRED) $505.00'),
  ('D2753', 'Crown – porcelain fused to titanium and titanium alloys (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2753 Crown – porcelain fused to titanium and titanium alloys (TOOTH) (PA REQUIRED) $505.00'),
  ('D2780', 'Crown – ¾ cast high noble metal (TOOTH) (PA REQUIRED) $404.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2780 Crown – ¾ cast high noble metal (TOOTH) (PA REQUIRED) $404.00'),
  ('D2781', 'Crown – ¾ cast predominantly base metal (TOOTH) (PA REQUIRED) $404.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2781 Crown – ¾ cast predominantly base metal (TOOTH) (PA REQUIRED) $404.00'),
  ('D2782', 'Crown – ¾ cast noble metal (TOOTH) (PA REQUIRED) $404.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2782 Crown – ¾ cast noble metal (TOOTH) (PA REQUIRED) $404.00'),
  ('D2790', 'Crown – full cast high noble metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 33, 'D2790 Crown – full cast high noble metal (TOOTH) (PA REQUIRED) $505.00'),
  ('D2791', 'Crown – full cast predominately base metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2791 Crown – full cast predominately base metal (TOOTH) (PA REQUIRED) $505.00'),
  ('D2792', 'Crown – full cast noble metal (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2792 Crown – full cast noble metal (TOOTH) (PA REQUIRED) $505.00'),
  ('D2794', 'Crown – Titanium and titanium alloys (TOOTH) (PA REQUIRED) $505.00', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2794 Crown – Titanium and titanium alloys (TOOTH) (PA REQUIRED) $505.00 OTHER RESTORATIVE SERVICES For all prefabricated crowns (D2930, D2931, D2932, D2933, D2934) there must be supporting documentation substantiating the need for the crown (e.g. radiographic images).'),
  ('D2920', 'Re-cement or re-bond crown (TOOTH)', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2920 Re-cement or re-bond crown (TOOTH) Claims for recementation of a crown by the original provider within one year of placement, or claims for subsequent recementations of the same crown, will be pended for professional review. Documentation to justify the need and appropriateness of such recementations may be r equired as a condition for payment. $30.30'),
  ('D2930', 'Prefabricated stainless steel crown - primary tooth (TOOTH) $117.16', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2930 Prefabricated stainless steel crown - primary tooth (TOOTH) $117.16'),
  ('D2931', 'Prefabricated stainless steel crown - permanent tooth (TOOTH) $117.16', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2931 Prefabricated stainless steel crown - permanent tooth (TOOTH) $117.16'),
  ('D2932', 'Prefabricated resin crown (TOOTH)', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2932 Prefabricated resin crown (TOOTH) Must encompass the complete clinical crown and should be utilized with the same criteria as for full crown construction. This procedure is limited to one occurrence per tooth within two years. If replacement becomes necessary during that time, claims submitted will be pended for professional review. To justify the appropriateness of replacements, documentation must be included as a claim attachment. Placement on deciduous anterior teeth is generally not reimbursable past the age of five (5) years of age, unless medically necessary based on the clinical needs of the individual member. $117.16'),
  ('D2933', 'Prefabricated stainless steel crown with resin window (TOOTH)', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2933 Prefabricated stainless steel crown with resin window (TOOTH) Restricted to primary anterior teeth, permanent maxillary bicuspids and first molars. $131.30'),
  ('D2934', 'Prefabricated esthetic coated stainless steel crown – primary tooth (TOOTH) $131.30', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2934 Prefabricated esthetic coated stainless steel crown – primary tooth (TOOTH) $131.30'),
  ('D2951', 'Pin retention – per tooth, in addition to restoration (TOOTH) $29.29', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2951 Pin retention – per tooth, in addition to restoration (TOOTH) $29.29'),
  ('D2952', 'Post and core in addition to crown, indirectly fabricated (TOOTH) $126.25', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2952 Post and core in addition to crown, indirectly fabricated (TOOTH) $126.25'),
  ('D2954', 'Prefabricated post and core in addition to crown (TOOTH)', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2954 Prefabricated post and core in addition to crown (TOOTH) There is no separate reimbursement for the core material. $126.25'),
  ('D2955', 'Post removal (TOOTH) $95.95', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2955 Post removal (TOOTH) $95.95'),
  ('D2980', 'Crown repair necessitated by restorative material failure (TOOTH) (REPORT NEEDED) (BR)', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2980 Crown repair necessitated by restorative material failure (TOOTH) (REPORT NEEDED) (BR)'),
  ('D2999', 'Unspecified restorative procedure, by report (REPORT NEEDED) (BR)', 'III. RESTORATIVE D2000-D2999', (select id from src), 34, 'D2999 Unspecified restorative procedure, by report (REPORT NEEDED) (BR) All radiographic images taken during the course of root canal therapy and all post- treatment radiographic images are included in the fee for the root canal procedure. At least one pre-treatment radiographic image demonstrating the need for the procedure, and one post-treatment radiographic image that demonstrates the result of the treatment, must be maintained in the member''s record. Surgical root canal treatment or apicoectomy may be considered appropriate and covered when the root canal system cannot be acceptably treated non-surgically, there is active root resorption, or access to the canal is obstructed. Treatment may also be covered where there is gross over or under extension of the root canal filling, periapical or lateral pathosis persists, or there is a fracture of the root. Pulp capping, either direct or indirect, is not reimbursable. Root canal therapy for members under the age of 21 will be covered when medically necessary. In determining whether a requested root canal is medically necessary, the following factors may be considered: • The periodontal status, member compliance and overall status and prognosis of the tooth is favorable. • The tooth is not routinely restorable with a filling. Root canal therapy for members 21 years of age and over will be covered when medically necessary. In determining whether requested endodontic treatment is medically necessary, the following factors may be considered: • There is a documented medical condition which precludes an extraction • The tooth is a critical abutment for an existing or proposed prosthesis • If the tooth is a posterior tooth, the following additional factors may be considered: o The periodontal status, member compliance and overall status and prognosis of the tooth is favorable o There are eight or more natural or prosthetic posterior points of contact present o If the posterior tooth is a molar, treatment of the molar is necessary to maintain functional or balanced occlusion of the patient''s dentition o Consideration for a third molar will be given if the third molar occupies the first or second molar position o Note: Requests for treatment on unopposed molars must include a narrative documenting medical necessity • If the tooth is an anterior tooth, the following additional factors may be considered: o The periodontal status, member compliance and overall status and prognosis of the tooth is favorable. PULPOTOMY'),
  ('D3230', 'Pulpal therapy (resorbable filling) – anterior, primary tooth (excluding final restoration) (TOOTH)', 'IV. ENDODONTICS D3000-D3999', (select id from src), 35, 'D3230 Pulpal therapy (resorbable filling) – anterior, primary tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $151.50'),
  ('D3240', 'Pulpal therapy (resorbable filling) – posterior, primary tooth (excluding final restoration) (TOOTH)', 'IV. ENDODONTICS D3000-D3999', (select id from src), 35, 'D3240 Pulpal therapy (resorbable filling) – posterior, primary tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $237.35 ENDODONTIC THERAPY (INCLUDING TREATMENT PLAN, CLINICAL PROCEDURES AND FOLLOW-UP CARE) Includes primary teeth without succedaneous teeth and permanent teeth.'),
  ('D3310', 'Endodontic therapy – anterior tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $252.50', 'IV. ENDODONTICS D3000-D3999', (select id from src), 35, 'D3310 Endodontic therapy – anterior tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $252.50'),
  ('D3320', 'Endodontic therapy – premolar tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $303.00', 'IV. ENDODONTICS D3000-D3999', (select id from src), 35, 'D3320 Endodontic therapy – premolar tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $303.00'),
  ('D3330', 'Endodontic therapy – molar tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $404.00', 'IV. ENDODONTICS D3000-D3999', (select id from src), 35, 'D3330 Endodontic therapy – molar tooth (excluding final restoration) (TOOTH) (PA REQUIRED) $404.00 ENDODONTIC RETREATMENT'),
  ('D3346', 'Retreatment of previous root canal therapy – anterior (TOOTH) (PA REQUIRED) $252.50', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3346 Retreatment of previous root canal therapy – anterior (TOOTH) (PA REQUIRED) $252.50'),
  ('D3347', 'Retreatment of previous root canal therapy – premolar (TOOTH) (PA REQUIRED) $303.00', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3347 Retreatment of previous root canal therapy – premolar (TOOTH) (PA REQUIRED) $303.00'),
  ('D3348', 'Retreatment of previous root canal therapy - molar (TOOTH) (PA REQUIRED) $404.00', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3348 Retreatment of previous root canal therapy - molar (TOOTH) (PA REQUIRED) $404.00 APEXIFICATION / RECALCIFICATION PROCEDURES'),
  ('D3351', 'Apexification / recalcification - initial visit (apical closure/calcific repair of perforations, root', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3351 Apexification / recalcification - initial visit (apical closure/calcific repair of perforations, root resorption, etc.) (TOOTH) Includes opening tooth, pulpectomy, preparation of canal spaces, first placement of medication and necessary radiographic images. (This procedure includes first phase of complete root canal therapy.) $82.82'),
  ('D3352', 'Apexification / recalcification - interim medication replacement (TOOTH)', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3352 Apexification / recalcification - interim medication replacement (TOOTH) For visits in which the intra-canal medication is replaced with new medication. Includes any necessary radiographs. There may be several of these visits. The published fee is the maximum reimbursable amount regardless of the number of visits. $80.80'),
  ('D3353', 'Apexification / recalcification - final visit (includes completed root canal therapy – apical', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3353 Apexification / recalcification - final visit (includes completed root canal therapy – apical closure/calcific repair of perforations, root resorption, etc.) (TOOTH) Includes the removal of intra-canal medication and procedures necessary to place final root canal filling material including necessary radiographs. (This procedure includes last phase of complete root canal therapy.) $104.03 APICOECTOMY Periradicular surgery is a term used to describe surgery to the root surface (e.g., apicoectomy), repair of a root perforation or resorptive defect, exploratory curettage to look for root fractures, removal of extruded filling materials or instruments, removal of broken root fragments, sealing of accessory canals, etc. This does not include retrograde filling material placement. Performed as a separate surgical procedure and includes periapical curettage.'),
  ('D3410', 'Apicoectomy - anterior (TOOTH) (PA REQUIRED) $161.60', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3410 Apicoectomy - anterior (TOOTH) (PA REQUIRED) $161.60'),
  ('D3421', 'Apicoectomy - premolar (first root) (TOOTH) (PA REQUIRED)', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3421 Apicoectomy - premolar (first root) (TOOTH) (PA REQUIRED) If more than one root is treated, see D3426. $161.60'),
  ('D3425', 'Apicoectomy - molar (first root) (TOOTH) (PA REQUIRED)', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3425 Apicoectomy - molar (first root) (TOOTH) (PA REQUIRED) If more than one root is treated, see D3426. $181.80'),
  ('D3426', 'Apicoectomy (each additional root) (TOOTH) (PA REQUIRED) $60.60', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3426 Apicoectomy (each additional root) (TOOTH) (PA REQUIRED) $60.60'),
  ('D3430', 'Retrograde filling - per root (TOOTH) (PA REQUIRED) $50.50', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3430 Retrograde filling - per root (TOOTH) (PA REQUIRED) $50.50 OTHER ENDODONTIC PROCEDURES'),
  ('D3999', 'Unspecified endodontic procedure, by report (REPORT NEEDED) (BR)', 'IV. ENDODONTICS D3000-D3999', (select id from src), 36, 'D3999 Unspecified endodontic procedure, by report (REPORT NEEDED) (BR) For details regarding the “PERIODONTICS” codes that are associated with the implant and implant related services benefit ONLY (D4245, D4273, D4275, D4277, D4278, D4283, D4285, D6106, D6107), see section VIII. IMPLANTS. SURGICAL SERVICES (INCLUDING USUAL POST-OPERATIVE CARE)'),
  ('D4210', 'and D4211 are reimbursable solely for the correction of severe hyperplasia or hypertrophy associated with drug', 'V. PERIODONTICS D4000-D4999', (select id from src), 37, 'D4210 and D4211 are reimbursable solely for the correction of severe hyperplasia or hypertrophy associated with drug therapy, hormonal disturbances, or congenital defects. The provider must keep in the treatment record detailed documentation describing the need for gingivectomy or gingivoplasty including pretreatment photographs depicting the condition of the tissues. D4210 Gingivectomy or gingivoplasty – four or more contiguous teeth or tooth bounded spaces per quadrant (QUAD) (REPORT NEEDED) $101.00'),
  ('D4211', 'Gingivectomy or gingivoplasty – one to three contiguous teeth or tooth bounded spaces per', 'V. PERIODONTICS D4000-D4999', (select id from src), 37, 'D4211 Gingivectomy or gingivoplasty – one to three contiguous teeth or tooth bounded spaces per quadrant (QUAD) (REPORT NEEDED) $65.65'),
  ('D4245', 'Apically positioned flap (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) $126.25', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 46, 'D4245 Apically positioned flap (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) $126.25'),
  ('D4249', 'Clinical Crown Lengthening – hard tissue (PA REQUIRED)', 'V. PERIODONTICS D4000-D4999', (select id from src), 37, 'D4249 Clinical Crown Lengthening – hard tissue (PA REQUIRED) Crown lengthening requires reflection of a full thickness flap and removal of bone, altering the crown to root ratio. The periodontal status, member compliance, and overall status and prognosis of the tooth may be taken into consideration when determining medical necessity. Crown lengthening is reimbursable solely when associated with medically necessary crown or root canal procedure. All requests for coverage of a crown lengthening should include a complete treatment plan addressing all areas of pathology. The provider must keep in the treatment record detailed documentation describing the need for crown lengthening including pretreatment photographs depicting the condition of the tissues. Coverage of a crown lengthening should be requested at the same time as a request for coverage of a crown and/or a root canal. If the need for crown lengthening is discovered during a procedure, then providers should refer to Prior Approval Change Request information. $75.00 NON-SURGICAL PERIODONTAL SERVICES'),
  ('D4273', 'Autogenous connective tissue graft procedure (including donor and recipient surgical sites) first', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 46, 'D4273 Autogenous connective tissue graft procedure (including donor and recipient surgical sites) first tooth, implant or edentulous tooth position in graft (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) There are two surgical sites. The recipient site utilizes a split thickness incision, retaining the overlapping flap of gingiva and/or mucosa. The connective tissue is dissected from a separate donor site leaving an epithelialized flap for closure. $303.00'),
  ('D4275', 'Non-autogenous connective tissue graft (including recipient site and donor material) – first tooth,', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 46, 'D4275 Non-autogenous connective tissue graft (including recipient site and donor material) – first tooth, implant, or edentulous tooth position in graft (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) $404.00'),
  ('D4277', 'Free soft tissue graft procedure (including recipient and donor surgical sites) first tooth, implant, or', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 46, 'D4277 Free soft tissue graft procedure (including recipient and donor surgical sites) first tooth, implant, or edentulous tooth position in graft (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) There is only a recipient surgical site utilizing split thickness incision, retaining the overlaying flap of gingiva and/or mucosa. A donor surgical site is not present. $404.00'),
  ('D4278', 'Free soft tissue graft procedure (including recipient and donor surgical sites) each additional', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 46, 'D4278 Free soft tissue graft procedure (including recipient and donor surgical sites) each additional contiguous tooth, implant, or edentulous tooth position in same graft site (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) Used in conjunction with D4277. $303.00'),
  ('D4283', 'Autogenous connective tissue graft procedure (including donor and recipient surgical sites) – each', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 46, 'D4283 Autogenous connective tissue graft procedure (including donor and recipient surgical sites) – each additional contiguous tooth, implant or edentulous tooth position in same graft site (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) Used in conjunction with D4273. $202.00'),
  ('D4285', 'Non-autogenous connective tissue graft procedure (including recipient surgical site and donor', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 46, 'D4285 Non-autogenous connective tissue graft procedure (including recipient surgical site and donor material) – each additional contiguous tooth, implant or edentulous tooth position in same graft site. (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) Used in conjunction with D4275. $303.00 The following procedure codes are a covered benefit only when associated with an implant or an implant-related service:'),
  ('D4341', 'Periodontal scaling and root planing – four or more teeth per quadrant (QUAD) $45.45', 'V. PERIODONTICS D4000-D4999', (select id from src), 37, 'D4341 Periodontal scaling and root planing – four or more teeth per quadrant (QUAD) $45.45'),
  ('D4342', 'Periodontal scaling and root planing – one to three teeth per quadrant (QUAD) $30.30', 'V. PERIODONTICS D4000-D4999', (select id from src), 37, 'D4342 Periodontal scaling and root planing – one to three teeth per quadrant (QUAD) $30.30 For periodontal scaling and root planing (D4341 and D4342) to be considered, the diagnostic materials must demonstrate the following, consistent with professional standards: • Clinical loss of periodontal attachment, and; o Periodontal pockets and sub-gingival accretions on cemental surfaces in the quadrant(s) being treated, and/or; o Radiographic evidence of crestal bone loss and changes in crestal lamina dura, and/or; o Radiographic evidence of root surface calculus. The provider must keep in the treatment record detailed documentation describing the need for periodontal scaling and root planing, including a copy of the pre-treatment evaluation of the periodontium, a general description of the tissues (e.g., color, shape, and consistency), the location and measurement of periodontal pockets, the description of the type and amount of bone loss, the periodontal diagnosis, the amount and location of subgingival calculus deposits, and tooth mobility. Treatment per quadrant is limited to once every two (2) years. For consideration of more frequent treatment prior approval with supporting documentation is required. Reimbursement for D4341 and/or D4342 is limited to no more than two quadrants on a single date of service. In exceptional circumstances, consideration may be given for reimbursement for more than two quadrants on a single date of service (e.g., treatment under anesthesia). These claims should be submitted using procedure code D4999 with documentation supporting both the need for treatment and the exceptional circumstances present. Prophylaxis or periodontal maintenance (e.g., D1110, D1120, D4910) will not be reimbursed on the same date of service as periodontal scaling and root planing (D4341, D4342). OTHER PERIODONTAL SERVICES'),
  ('D4910', 'Periodontal maintenance', 'V. PERIODONTICS D4000-D4999', (select id from src), 38, 'D4910 Periodontal maintenance This procedure is for members who have previously been treated for periodontal disease with procedures such as scaling and root planing (D4341 or D4342). D4910 cannot be used in conjunction with or billed within six (6) months of any other prophylaxis procedure (e.g., D1110). Reimbursement for D4910 is limited to once per six (6) months and cannot be used in conjunction with D4341 or D4342 on the same date of service. $45.45'),
  ('D4999', 'Unspecified periodontal procedure, by report (REPORT NEEDED) (BR)', 'V. PERIODONTICS D4000-D4999', (select id from src), 38, 'D4999 Unspecified periodontal procedure, by report (REPORT NEEDED) (BR) Full and /or partial dentures are covered by Medicaid when they are determined to be medically necessary, including when necessary to alleviate a serious health condition or one that is determined to affect employability. This service requires prior approval. Complete dentures and partial dentures, whether unserviceable, lost, stolen, or broken will not be replaced for a minimum of eight years from initial placement except when determined medically necessary by the Department or its agent. Prior approval requests for replacement dentures prior to eight years must include a completed Justification Replacement Prosthesis Form signed by the patient''s dentist, explaining the specific circumstances that necessitates replacement of the denture. If replacement dentures are requested within the eight-year period after they have already been replaced once, then the dentist''s supporting documentation must include an explanation of preventative measures instituted to alleviate the need for further replacements. General Guidelines for All Removable Prosthesis: • Requests for partial dentures will be reviewed based on the presence/absence of eight (8) points of natural or prosthetic posterior occlusal contact and/or one (1) missing maxillary anterior or two (2) missing mandibular anterior teeth. • Complete and/or partial dentures will be approved only when the existing prosthesis is not serviceable or cannot be relined or rebased. Reline or rebase of an existing prosthesis will not be reimbursed when such procedures are performed in addition to a new prosthesis for the same arch within 6 months of the delivery of a new prosthesis. Only “tissue conditioning” (D5850 or D5851) is payable within six (6) months prior to the delivery of a new prosthesis; • Six (6) months of post-delivery care from the date of insertion is included in the reimbursement for all newly fabricated prosthetic appliances. This includes rebasing, relining, adjustments and repairs. • Cleaning of removable prosthesis or soft tissue not directly related to natural teeth or implants is not a covered service. Prophylaxis and/or scaling and root planing is only payable when performed on natural dentition; • "Immediate" prosthetic appliances are not a covered service. An appropriate length of time for healing should be allowed before taking any final impressions. Generally, it is expected that tissues will need a minimum of four (4) to six (6) weeks for healing. Claims for denture insertion occurring within four (4) weeks of extraction(s) will pend for professional review; • Claims are not to be submitted until the denture(s) are completed and delivered to the member. The "date of service" used on the claim is the date that the denture(s) are delivered. If the prosthesis cannot be delivered or the member has lost eligibility following the date of the "decisive appointment," claims should be submitted following the guidelines for "Interrupted Treatment"; • Medicaid payment is considered payment in-full. Except for members with a "spend down," members cannot be charged beyond the Medicaid fee. Deposits, down-payments or advance payments are prohibited; • All treatment notes, radiographic images, laboratory prescriptions and laboratory invoices should be made part of the member''s treatment record to be made available upon request in support of any treatment provided, and • The total cost of repairs should not be excessive and should not exceed 50% of the cost of a new prosthesis. If the total cost of repairs and/or relines is to exceed 50% of the cost of a new prosthesis, a prior approval request for a new prosthesis should be submitted with a detailed description of the existing prosthesis including why any replacement would be necessary per Medicaid guidelines and would be more appropriate than repair of the existing prosthesis: Claims for repair or reline exceeding 50% of the cost of a new prosthesis may be subject to denial. COMPLETE DENTURES (INCLUDING ROUTINE POST-DELIVERY CARE) Radiographs are not routinely required to obtain prior approval for full dentures. The guidelines published by the ADA and the U.S. Department of Health and Human Services on the use of x-rays should be followed. Additional information is found here: The Selection of Patients for Dental Radiographic Examinations | FDA.'),
  ('D5110', 'Complete denture – maxillary (PA REQUIRED) $565.60', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 39, 'D5110 Complete denture – maxillary (PA REQUIRED) $565.60'),
  ('D5120', 'Complete denture – mandibular (PA REQUIRED) $565.60', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 39, 'D5120 Complete denture – mandibular (PA REQUIRED) $565.60 PARTIAL DENTURES (INCLUDING ROUTINE POST-DELIVERY CARE) Caries index, periodontal status, recipient compliance, dental history, medical history and the overall status and prognosis of the entire dentition, among other factors, will be taken into consideration when determining medical necessity. Please review Scope of Program and Non-Reimbursable Services (p 13) and Essential Services (p 23). Requirements for the placement of partial dentures are: • All phase I restorative treatment which includes extractions, removal of all decay and restoration with permanent filling materials, endodontic therapy, crowns, etc. must be completed prior to taking the final impression(s) for partial denture(s). • Partial dentures can be considered for ages 15 years and above; an “Interim Prosthesis” (procedure codes D5820 and/or D5821) can be considered for individuals 5 to 15 years of age.'),
  ('D5211', 'Maxillary partial denture - resin base (including retentive/clasping materials, rests, and teeth) (PA', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 39, 'D5211 Maxillary partial denture - resin base (including retentive/clasping materials, rests, and teeth) (PA REQUIRED) $353.50'),
  ('D5212', 'Mandibular partial denture - resin base (including retentive/clasping materials, rests, and teeth)', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 39, 'D5212 Mandibular partial denture - resin base (including retentive/clasping materials, rests, and teeth) (PA REQUIRED) $353.50'),
  ('D5213', 'Maxillary partial denture - cast metal framework with resin denture bases (including', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 39, 'D5213 Maxillary partial denture - cast metal framework with resin denture bases (including retentive/clasping materials, rests and teeth) (PA REQUIRED) $565.60'),
  ('D5214', 'Mandibular partial denture - cast metal framework with resin denture bases (including', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 39, 'D5214 Mandibular partial denture - cast metal framework with resin denture bases (including retentive/clasping materials, rests and teeth) (PA REQUIRED) $565.60'),
  ('D5225', 'Maxillary partial denture - flexible base (including retentive/clasping materials, rests and teeth) (PA', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5225 Maxillary partial denture - flexible base (including retentive/clasping materials, rests and teeth) (PA REQUIRED) $565.60'),
  ('D5226', 'Mandibular partial denture - flexible base (including retentive/clasping materials, rests and teeth)', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5226 Mandibular partial denture - flexible base (including retentive/clasping materials, rests and teeth) (PA REQUIRED) $565.60 ADJUSTMENTS TO DENTURES Adjustments within six months of the delivery of the prosthesis are considered part of the payment for the prosthesis. Adjustments (procedure codes D5410, D5411, D5421, and D5422) are not reimbursable on the same date of service as the initial insertion of the prosthetic appliance; OR on the same date of service as any repair, rebase, or reline procedure code.'),
  ('D5410', 'Adjust complete denture – maxillary $25.25', 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', (select id from src), 40, 'D5410 Adjust complete denture – maxillary $25.25 D5410 – D5422). $25.25'),
  ('D5411', 'Adjust complete denture – mandibular $25.25', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5411 Adjust complete denture – mandibular $25.25'),
  ('D5421', 'Adjust partial denture – maxillary $25.25', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5421 Adjust partial denture – maxillary $25.25'),
  ('D5422', 'Adjust partial denture – mandibular $25.25', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5422 Adjust partial denture – mandibular $25.25 PROSTHETIC APPLIANCE REPAIRS Limitation: The total cost of repairs should not be excessive and should not exceed 50% of the cost of a new prosthesis. If the total cost of repairs is to exceed 50% of the cost of a new prosthesis, a prior approval request for a new prosthesis should be submitted with a detailed description of the existing prosthesis and why any replacement would be necessary per Medicaid guidelines and would be more appropriate than repair of the existing prosthesis. REPAIRS TO COMPLETE DENTURES'),
  ('D5511', 'Repair broken complete denture base, mandibular $65.65', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5511 Repair broken complete denture base, mandibular $65.65'),
