  ('D5650', 'Add tooth to existing partial denture-per tooth (TOOTH) $65.65', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5650 Add tooth to existing partial denture-per tooth (TOOTH) $65.65'),
  ('D5660', 'Add clasp to existing partial denture - per tooth (TOOTH) $103.02', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 40, 'D5660 Add clasp to existing partial denture - per tooth (TOOTH) $103.02 DENTURE REBASE PROCEDURES Rebase procedures are not payable within six months prior to the delivery of a new prosthesis. Only “tissue conditioning” (D5850 and D5851) is payable within six months prior to the delivery of a new prosthesis.'),
  ('D5710', 'Rebase - complete maxillary denture (PA REQUIRED) $171.70', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5710 Rebase - complete maxillary denture (PA REQUIRED) $171.70'),
  ('D5711', 'Rebase - complete mandibular denture (PA REQUIRED) $171.70', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5711 Rebase - complete mandibular denture (PA REQUIRED) $171.70'),
  ('D5720', 'Rebase - maxillary partial denture (PA REQUIRED) $175.74', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5720 Rebase - maxillary partial denture (PA REQUIRED) $175.74'),
  ('D5721', 'Rebase – mandibular partial denture (PA REQUIRED) $175.74', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5721 Rebase – mandibular partial denture (PA REQUIRED) $175.74 DENTURE RELINE PROCEDURES Reline procedures are not payable within six months prior to the delivery of a new prosthesis. For cases in which it is impractical to complete a laboratory reline, prior approval for an office (“chairside” or “cold cure”) reline may be requested with credible documentation which would preclude a laboratory reline. Only “tissue conditioning” (D5850 and D5851) is payable within six months prior to the delivery of a new prosthesis.'),
  ('D5730', 'Reline complete maxillary denture (direct) (PA REQUIRED) $126.25', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5730 Reline complete maxillary denture (direct) (PA REQUIRED) $126.25'),
