  ('D5760', 'Reline maxillary partial denture (indirect) $126.25', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5760 Reline maxillary partial denture (indirect) $126.25'),
  ('D5761', 'Reline mandibular partial denture (indirect) $126.25', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5761 Reline mandibular partial denture (indirect) $126.25 INTERIM PROSTHESIS Reimbursement is limited to once per year and only for children between 5 and 15 years of age. Codes D5820 and D5821 are not to be used in lieu of space maintainers. All claims will be pended for professional review prior to payment.'),
  ('D5820', 'Interim partial denture (including retentive/clasping materials, rests, and teeth), maxillary $175.74', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5820 Interim partial denture (including retentive/clasping materials, rests, and teeth), maxillary $175.74'),
  ('D5821', 'Interim partial denture (including retentive/clasping materials, rests, and teeth), mandibular $175.74', 'VI. PROSTHODONTICS (Removable) D5000-D5899', (select id from src), 41, 'D5821 Interim partial denture (including retentive/clasping materials, rests, and teeth), mandibular $175.74 OTHER REMOVABLE PROSTHETIC SERVICES Codes D5850 and D5851 are for treatment reline using materials designed to heal unhealthy ridges prior to more definitive final restoration. This is the ONLY type of reline reimbursable within six (6) months prior to the delivery of a new prosthesis. Insertion of tissue conditioning liners in existing dentures will be limited to once per denture unit. D5850 and'),
