  ('D6191', 'Semi-precision abutment - placement (TOOTH) (PA REQUIRED)', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 45, 'D6191 Semi-precision abutment - placement (TOOTH) (PA REQUIRED) This procedure is the initial placement, or replacement, or a semi-precision abutment on the implant body. $202.00'),
  ('D6192', 'Semi-precision attachment - placement (TOOTH) (PA REQUIRED)', 'VIII. IMPLANT SERVICES D6000-D6199', (select id from src), 45, 'D6192 Semi-precision attachment - placement (TOOTH) (PA REQUIRED) This procedure involves the luting of the initial, or replacement, semi-precision attachment to the removable prosthesis. $50.50'),
