  ('D6930', 'Re-cement or re-bond fixed partial denture (QUAD) $45.45', 'IX. PROSTHODONTICS, FIXED D6200-D6999', (select id from src), 49, 'D6930 Re-cement or re-bond fixed partial denture (QUAD) $45.45'),
  ('D6980', 'Fixed partial denture repair necessitated by restorative material failure (QUAD) (REPORT', 'IX. PROSTHODONTICS, FIXED D6200-D6999', (select id from src), 49, 'D6980 Fixed partial denture repair necessitated by restorative material failure (QUAD) (REPORT NEEDED) For sectioning of a fixed partial denture, use procedure code D9120. (BR)'),
  ('D6999', 'Unspecified, fixed prosthodontic procedure, by report (REPORT NEEDED) (BR)', 'IX. PROSTHODONTICS, FIXED D6200-D6999', (select id from src), 49, 'D6999 Unspecified, fixed prosthodontic procedure, by report (REPORT NEEDED) (BR) For details regarding the “ORAL AND MAXILLOFACIAL SURGERY” codes that are associated with the implant and implant- related services benefit ONLY (D7951, D7953), see section VIII. IMPLANTS. All surgical procedures include the surgery and the follow-up care for the period indicated after the procedure description (e.g. (POST OPERATIVE CARE: 7 DAYS)). Necessary follow-up care beyond the listed period should be billed using codes'),
  ('D7111', 'Extraction, coronal remnants – primary tooth (TOOTH) $35.35', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 49, 'D7111 Extraction, coronal remnants – primary tooth (TOOTH) $35.35'),
  ('D7140', 'Extraction, erupted tooth or exposed root (elevation and/or forceps removal) (TOOTH) (POST', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 49, 'D7140 Extraction, erupted tooth or exposed root (elevation and/or forceps removal) (TOOTH) (POST OPERATIVE CARE: 3 DAYS) $50.50'),
