  ('D7261', 'Primary closure of sinus perforation (QUAD 10 or 20) (POST OPERATIVE CARE: 14 DAYS) $202.00', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 50, 'D7261 Primary closure of sinus perforation (QUAD 10 or 20) (POST OPERATIVE CARE: 14 DAYS) $202.00'),
  ('D7270', 'Tooth re-implantation and/or stabilization of accidentally evulsed or displaced tooth (TOOTH)', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 50, 'D7270 Tooth re-implantation and/or stabilization of accidentally evulsed or displaced tooth (TOOTH) (POST OPERATIVE CARE: 30 DAYS). Includes splinting and/or stabilization. $115.14'),
  ('D7272', 'Tooth transplantation (includes re-implantation from one site to another and splinting and/or', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 50, 'D7272 Tooth transplantation (includes re-implantation from one site to another and splinting and/or stabilization) (TOOTH) (POST OPERATIVE CARE: 30 DAYS) $151.50'),
  ('D7280', 'Exposure of an unerupted tooth (TOOTH) (POST OPERATIVE CARE: 14 DAYS)', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 50, 'D7280 Exposure of an unerupted tooth (TOOTH) (POST OPERATIVE CARE: 14 DAYS) An incision is made, and the tissue is reflected, and bone removed as necessary to expose the crown of an impacted tooth not intended to be extracted. $292.90'),
  ('D7283', 'Placement of device to facilitate eruption of impacted tooth (TOOTH) (POST OPERATIVE CARE: 14', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 50, 'D7283 Placement of device to facilitate eruption of impacted tooth (TOOTH) (POST OPERATIVE CARE: 14 DAYS) Report the surgical exposure separately using D7280. $50.50'),
  ('D7285', 'Incisional biopsy of oral tissue - hard (bone, tooth) (REPORT NEEDED) (POST OPERATIVE CARE: 30', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 6, 'D7285 & D7286 Incisional Biopsy of Oral Tissue Addition of Language: Description of Incisional Biopsy of Oral Tissue D7285 Incisional biopsy of oral tissue - hard (bone, tooth) (REPORT NEEDED) (POST OPERATIVE CARE: 30 DAYS) For partial removal of lesion. This procedure involves biopsy of osseous or intra-osseous lesions (example cyst, tumor) and is not used for apicoectomy/periradicular surgery. This procedure does not entail an excision. Claims must be submitted on paper with a copy of the operative report, including the description and location of the lesion and pathology report. $105.04'),
  ('D7286', 'Incisional biopsy of oral tissue – soft (REPORT NEEDED) (POST OPERATIVE CARE: 30 DAYS)', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 50, 'D7286 Incisional biopsy of oral tissue – soft (REPORT NEEDED) (POST OPERATIVE CARE: 30 DAYS) For partial removal of a lesion. This procedure is not used at the same time as codes for apicoectomy/periradicular curettage. This procedure does not entail an excision. Claims must be submitted on paper with a copy of the operative report, including the description and location of the lesion and pathology report. $84.84'),
  ('D7290', 'Surgical repositioning of teeth (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 60 DAYS) $146.45', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 50, 'D7290 Surgical repositioning of teeth (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 60 DAYS) $146.45 Alveoloplasty - Preparation of Ridge'),
  ('D7310', 'Alveoloplasty in conjunction with extractions – four or more teeth or tooth spaces, per quadrant', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 51, 'D7310 Alveoloplasty in conjunction with extractions – four or more teeth or tooth spaces, per quadrant (QUAD) (POST OPERATIVE CARE: 14 DAYS) This procedure will be reimbursed when additional surgical procedures above and beyond the removal of the teeth are required to prepare the ridge for dentures. Not reimbursable in addition to surgical extractions in the same quadrant. Claims should be submitted on the same invoice as extractions to expedite review. $70.70'),
  ('D7311', 'Alveoloplasty in conjunction with extractions – one to three teeth or tooth spaces, per quadrant', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 51, 'D7311 Alveoloplasty in conjunction with extractions – one to three teeth or tooth spaces, per quadrant (QUAD) (POST OPERATIVE CARE: 14 DAYS) This procedure will be reimbursed when additional surgical procedures above and beyond the removal of the teeth are required to prepare the ridge for dentures. Not reimbursable in addition to surgical extractions in the same quadrant. Claims should be submitted on the same invoice as extractions to expedite review. $50.50'),
  ('D7320', 'Alveoloplasty not in conjunction with extractions – four or more teeth or tooth spaces, per quadrant', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 51, 'D7320 Alveoloplasty not in conjunction with extractions – four or more teeth or tooth spaces, per quadrant (QUAD) (POST OPERATIVE CARE: 14 DAYS) The fee for each quadrant includes the recontouring of both osseous and soft tissues in that quadrant. Will not be reimbursed in conjunction with procedure code D7310 in the same quadrant. $116.15'),
  ('D7321', 'Alveoloplasty not in conjunction with extractions – one to three or tooth spaces, per quadrant', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 51, 'D7321 Alveoloplasty not in conjunction with extractions – one to three or tooth spaces, per quadrant (QUAD) (POST OPERATIVE CARE: 14 DAYS) The fee for each quadrant includes the recontouring of both osseous and soft tissues in that quadrant. Will not be reimbursed in conjunction with procedure code D7311 in the same quadrant. $75.75 Vestibuloplasty Vestibuloplasty may be approved when a denture could not otherwise be worn.'),
  ('D7340', 'Vestibuloplasty - ridge extension (secondary epithelialization) (ARCH) (PA REQUIRED) (POST', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 51, 'D7340 Vestibuloplasty - ridge extension (secondary epithelialization) (ARCH) (PA REQUIRED) (POST OPERATIVE CARE: 60 DAYS) $303.00'),
  ('D7350', 'Vestibuloplasty - ridge extension (including soft tissue grafts, muscle reattachment, revision of soft', 'X. ORAL AND MAXILLOFACIAL SURGERY D7000-D7999', (select id from src), 51, 'D7350 Vestibuloplasty - ridge extension (including soft tissue grafts, muscle reattachment, revision of soft tissue attachment and management of hypertrophied and hyperplastic tissue) (ARCH) (PA REQUIRED) (POST OPERATIVE CARE: 60 DAYS) $404.00 Excision of Soft Tissue Lesions (Includes Non-Odontogenic Cysts) All claims for D7410, D7411, and D7412, must be submitted with a copy of the operative report and all claims for D7413,'),
